# ChatML messages format for instruction fine-tuning
def format_chatml(messages):
    result = ''
    for msg in messages:
        result += f"<|im_start|>{msg['role']}\n{msg['content']}<|im_end|>\n"
    return result

# Alpaca-style single-turn format
def format_alpaca(example):
    if example.get('input'):
        prompt = f"### Instruction:\n{example['instruction']}\n\n### Input:\n{example['input']}\n\n### Response:\n"
    else:
        prompt = f"### Instruction:\n{example['instruction']}\n\n### Response:\n"
    return prompt + example['output'] + '\n'

import torch
from transformers import AutoModelForCausalLM, AutoTokenizer
import json

class FineTuneEvaluator:
    def __init__(self, model_path):
        self.tokenizer = AutoTokenizer.from_pretrained(model_path)
        self.model = AutoModelForCausalLM.from_pretrained(
            model_path, device_map='auto', torch_dtype=torch.float16
        )

    def generate(self, prompt, max_new_tokens=512):
        inputs = self.tokenizer(prompt, return_tensors='pt').to(self.model.device)
        with torch.no_grad():
            out = self.model.generate(
                **inputs,
                max_new_tokens=max_new_tokens,
                do_sample=False,
            )
        return self.tokenizer.decode(
            out[0][inputs['input_ids'].shape[1]:], skip_special_tokens=True
        )

    def eval_format_compliance(self, examples):
        compliant = 0
        for ex in examples:
            output = self.generate(ex['prompt'])
            try:
                json.loads(output)
                compliant += 1
            except json.JSONDecodeError:
                pass
        return compliant / len(examples)

    def eval_exact_match(self, examples):
        correct = sum(
            1 for ex in examples
            if self.generate(ex['prompt']).strip().lower() == ex['expected'].lower()
        )
        return correct / len(examples)

